public boolean writeValue(int statusAfterValue, String fieldNameToUse) throws IOException {

    if (!isOk()) {
        throw new IllegalStateException("No current value to start writing");
    }

    /* We got name or index - can only be name */
    if (fieldNameToUse != null && _currentName != null ){
        throw new IllegalArgumentException("JsonWriteContext.writeValue(): Can only call with null OR without 'fieldName', but found both.");
    }else if ((statusAfterValue & JsonStreamConstants.STATUS_HAS_NEXT_FIELD) == 0){
         setCurrentName(null); // clear cache for later lookups.
    } else {
        if( fieldNameToUse != null) { 
            setCurrentName(fieldNameToUse);
            _jg.serialize(new MinimalArraySerializer._1()); 
            _jg._setCurrentValue(_values[_valueIndex], _types[_valueIndex]);  
            resetValueBuffer();
            ++_idxOfValuesList;
        } else {
            --_index;
        }
    }

    /* Now what we have depends on next:
    /  array starts (or array element after colon):
     */
    if ((statusAfterValue & JsonStreamConstants.STATUS_START_ARRAY) > 0) {
        _type = TYPE_ARRAY;
        _valuesStart = _index;
        ++_index;
        return true;
    }
    ++_index;
    return false;
}

